import OrderListItem from "@/components/orderListItem";
import { useState } from "react";
import "../app/globals.css";

export interface IOrder {
  id: number;
  orderItems: IOrderItem[];
}

export interface IOrderItem {
  id: number;
  productId: number;
  name: string;
  description: string;
  count: number;
}

export default function Order() {
  const queryClient = useQueryClient();

  const { data: products, isLoading } = useQuery({
    queryKey: ["products"],
    queryFn: getProducts,
  });

  const [orders, setOrders] = useState<IOrder>({
    id: 1,
    orderItems: [
      {
        id: 1,
        productId: 1,
        name: "Table",
        description: "Dining table",
        count: 1,
      },
      {
        id: 2,
        productId: 2,
        name: "Chair",
        description: "Office chair",
        count: 1,
      },
    ],
  });

  const increment = (id: number) => {
    setOrders((prev) => ({
      ...prev,
      orderItems: prev.orderItems.map((item) =>
        item.id === id ? { ...item, count: item.count + 1 } : item
      ),
    }));
  };

  const decrement = (id: number) => {
    if (orders.orderItems.find((item) => item.id === id)?.count === 1)
      return setOrders((prev) => ({
        ...prev,
        orderItems: prev.orderItems.filter((item) => item.id !== id),
      }));

    setOrders((prev) => ({
      ...prev,
      orderItems: prev.orderItems.map((item) =>
        item.id === id ? { ...item, count: item.count - 1 } : item
      ),
    }));
  };

  const totalQuantity = orders.orderItems.reduce((acc, item) => {
    return acc + item.count;
  }, 0);

  return (
    <div className="flex flex-col min-h-screen items-center justify-center bg-zinc-100 pt-4 pb-4">
      {!!orders.orderItems.length && (
        <p className="mb-4">Total: {totalQuantity}</p>
      )}
      <div className="flex flex-col items-center justify-center w-100 gap-4">
        {orders.orderItems.length ? (
          orders.orderItems.map((item: IOrderItem) => (
            <OrderListItem
              key={`order-item-${item.id}`}
              id={item.id}
              name={item.name}
              description={item.description}
              productId={item.productId}
              count={item.count}
              increment={increment}
              decrement={decrement}
            />
          ))
        ) : (
          <p className="mt-4 mb-4">No orders</p>
        )}
      </div>
    </div>
  );
}
