import React from "react";
import {
  Item,
  ItemActions,
  ItemContent,
  ItemDescription,
  ItemTitle,
} from "./ui/item";
import { Button } from "./ui/button";
import { IOrderItem } from "@/pages/order";

interface IOrderListItem extends IOrderItem {
  increment: (value: number) => void;
  decrement: (value: number) => void;
}

const OrderListItem: React.FC<IOrderListItem> = ({
  id,
  name,
  count,
  productId,
  description,
  increment,
  decrement,
}) => {
  return (
    <Item className="w-100" variant="outline">
      <ItemContent>
        <ItemTitle>{name}</ItemTitle>
        <ItemDescription>{description}</ItemDescription>
      </ItemContent>
      <p>{count}</p>
      <ItemActions>
        <Button
          variant="outline"
          size="sm"
          onClick={() => increment(productId)}
        >
          +
        </Button>
        <Button
          variant="outline"
          size="sm"
          onClick={() => decrement(productId)}
        >
          -
        </Button>
      </ItemActions>
    </Item>
  );
};

export default OrderListItem;
